css:
.ps-country-chips { display: flex; flex-wrap: wrap; gap: var(--pds-space-1); }
.ps-chip { display: inline-flex; align-items: center; height: 2.25rem; padding: 0 var(--pds-space-2); border-radius: 1.125rem; border: 1px solid var(--pds-border-subtle); background: var(--pds-surface-layer); color: var(--pds-text-primary); font-size: 0.875rem; cursor: pointer; transition: background-color var(--pds-duration-base), border-color var(--pds-duration-base); min-height: 44px; }
.ps-chip:hover { background: var(--pds-surface-layer-hover); }
.ps-chip--active, .ps-chip[aria-checked='true'] { background: var(--pds-brand-blue-60); border-color: var(--pds-brand-blue-60); color: var(--pds-text-on-color); }
.ps-chip:focus-visible { outline: 2px solid var(--pds-focus-ring); outline-offset: 2px; }
@media (prefers-reduced-motion: reduce) { .ps-chip { transition: none; } }
